"use client";

import { Trash2 } from "lucide-react";
import { Button } from "@/components/ui/button";

export function DeletePortfolioButton({ id }: { id: string }) {
    const handleDelete = async (e: React.MouseEvent) => {
        e.preventDefault(); // Evitamos que el clic active el <Link> de la tarjeta
        e.stopPropagation();

        if (!confirm("Are you sure you want to decommission this strategy? All data will be lost.")) return;

        try {
            const res = await fetch(`http://localhost:8080/api/portfolios/${id}`, {
                method: "DELETE"
            });
            if (res.ok) {
                window.location.reload();
            }
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <Button
            variant="ghost"
            size="icon"
            onClick={handleDelete}
            className="h-8 w-8 text-slate-600 hover:text-red-400 hover:bg-red-400/10 transition-colors"
        >
            <Trash2 className="w-4 h-4" />
        </Button>
    );
}
