"use client";

import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Plus } from "lucide-react";

export function CreatePortfolioDialog() {
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [name, setName] = useState("");

    const handleCreate = async () => {
        if (!name) return;
        setLoading(true);
        try {
            const userId = "00000000-0000-0000-0000-000000000000"; // ID de prueba
            const res = await fetch("http://localhost:8080/api/portfolios", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    name,
                    userId,
                    balance: 0,
                    cumulativeDeposits: 0,
                    cumulativeWithdrawals: 0
                })
            });

            if (res.ok) {
                setOpen(false);
                setName("");
                window.location.reload();
            }
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button className="bg-white text-black hover:bg-slate-200 font-bold gap-2">
                    <Plus className="w-4 h-4" /> NEW STRATEGY
                </Button>
            </DialogTrigger>
            <DialogContent className="glass border-none text-white sm:max-w-md">
                <DialogHeader>
                    <DialogTitle className="text-2xl font-bold tracking-tighter uppercase italic">
                        Initialize Strategy
                    </DialogTitle>
                </DialogHeader>
                <div className="space-y-4 py-4">
                    <div className="space-y-2">
                        <label className="text-xs uppercase tracking-[0.2em] text-slate-500">Strategy Workspace Name</label>
                        <Input
                            placeholder="e.g. Aggressive_Growth_H1"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            className="bg-black/40 border-white/10 text-white placeholder:text-slate-700"
                        />
                    </div>
                </div>
                <DialogFooter>
                    <Button
                        onClick={handleCreate}
                        disabled={loading}
                        className="w-full bg-white text-black hover:bg-slate-200 font-bold uppercase tracking-widest"
                    >
                        {loading ? "INITIALIZING..." : "DEPLOY STRATEGY"}
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
}
